-- ---------- Working hours (Sun=0 .. Sat=6); off on Friday (5) ----------
INSERT INTO working_hours (staff_id, day_of_week, start_time, end_time, is_day_off)
SELECT s.id, d.dow, '10:00'::time, '18:00'::time, (d.dow = 5)
FROM staff s CROSS JOIN generate_series(0,6) AS d(dow)
ON CONFLICT (staff_id, day_of_week) DO NOTHING;

